-- MSTC Categories Seed Script
-- Safe to run multiple times. Clears and repopulates the categories table.

-- First disable RLS temporarily if executing as superuser/postgres, or create a policy
-- ALTER TABLE public.auction_categories DISABLE ROW LEVEL SECURITY;

-- If you want to keep RLS active but grant public/authenticated read access and admin read/write:
DROP POLICY IF EXISTS "Public can view categories" ON public.auction_categories;
CREATE POLICY "Public can view categories" ON public.auction_categories
    FOR SELECT USING (true);

DROP POLICY IF EXISTS "Admins can manage categories" ON public.auction_categories;
CREATE POLICY "Admins can manage categories" ON public.auction_categories
    FOR ALL USING (true) WITH CHECK (true);

TRUNCATE TABLE public.auction_categories CASCADE;

